// GET  /api/emails ΓÇö list emails for a contact
// POST /api/emails ΓÇö send an outbound email (multipart/form-data or JSON)

import { NextResponse } from 'next/server'
import { z } from 'zod'
import { getSession } from '@/lib/auth'
import { sendEmail, getEmailThread } from '@/lib/communications/email-service'

const sendSchema = z.object({
  contactId:  z.string(),
  subject:    z.string().min(1),
  body:       z.string().min(1), // HTML
  toEmail:    z.string().email(),
  fromEmail:  z.string().email().optional(),
  ccEmails:   z.array(z.string().email()).optional(),
  templateId: z.string().optional(),
})

export async function GET(request: Request) {
  const session = await getSession()
  if (!session) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })

  const { searchParams } = new URL(request.url)
  const contactId = searchParams.get('contactId')
  if (!contactId) return NextResponse.json({ error: 'contactId is required' }, { status: 400 })

  const page     = parseInt(searchParams.get('page')     ?? '1')
  const pageSize = parseInt(searchParams.get('pageSize') ?? '20')
  const result   = await getEmailThread(contactId, { page, pageSize })
  return NextResponse.json(result)
}

export async function POST(request: Request) {
  const session = await getSession()
  if (!session) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })

  try {
    const contentType = request.headers.get('content-type') ?? ''

    let fields: Record<string, string> = {}
    let attachments: Array<{ filename: string; content: Buffer }> = []

    if (contentType.includes('multipart/form-data')) {
      const formData = await request.formData()
      for (const [key, value] of formData.entries()) {
        if (value instanceof File) {
          const buffer = Buffer.from(await value.arrayBuffer())
          attachments.push({ filename: value.name, content: buffer })
        } else {
          fields[key] = value
        }
      }
    } else {
      fields = await request.json()
    }

    // ccEmails may arrive as a JSON string when sent via FormData
    if (typeof fields.ccEmails === 'string') {
      try { (fields as Record<string, unknown>).ccEmails = JSON.parse(fields.ccEmails) } catch { /* leave as-is */ }
    }

    const parsed = sendSchema.parse(fields)
    const email  = await sendEmail({
      ...parsed,
      sentById:    session.id,
      attachments: attachments.length > 0 ? attachments : undefined,
    })
    return NextResponse.json({ data: email }, { status: 201 })
  } catch (error) {
    if (error instanceof z.ZodError) return NextResponse.json({ error: error.errors }, { status: 400 })
    console.error('[POST /api/emails]', error)
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}

import { NextResponse } from 'next/server'
import * as fs from 'fs'
import * as path from 'path'
import { execSync } from 'child_process'
import { randomBytes } from 'crypto'

export const dynamic = 'force-dynamic'

const ROOT = process.cwd()
const ENV_PATH = path.join(ROOT, '.env')
const SCHEMA_PATH = path.join(ROOT, 'prisma', 'schema.prisma')

function isAlreadySetup(): boolean {
  if (!fs.existsSync(ENV_PATH)) return false
  const content = fs.readFileSync(ENV_PATH, 'utf8')
  const match = content.match(/^JWT_SECRET=(.+)$/m)
  if (!match) return false
  const secret = match[1].trim().replace(/^["']|["']$/g, '')
  return (
    secret.length >= 32 &&
    secret !== 'change_me_to_a_long_random_string_at_least_32_chars'
  )
}

export async function GET() {
  return NextResponse.json({ configured: isAlreadySetup() })
}

export async function POST(req: Request) {
  if (isAlreadySetup()) {
    return NextResponse.json(
      { error: 'Application is already configured.' },
      { status: 403 }
    )
  }

  let body: Record<string, string | undefined>
  try {
    body = await req.json()
  } catch {
    return NextResponse.json({ error: 'Invalid request body.' }, { status: 400 })
  }

  const {
    environment,
    dbHost, dbPort, dbName, dbUser, dbPass,
    adminName, adminEmail, adminPassword,
    appUrl,
    smtpHost, smtpPort, smtpUser, smtpPass, smtpFrom,
    twilioSid, twilioToken, twilioFrom,
  } = body

  if (!adminName || !adminEmail || !adminPassword) {
    return NextResponse.json(
      { error: 'Admin name, email, and password are required.' },
      { status: 400 }
    )
  }

  const isProduction = environment === 'production'
  const dbProvider = isProduction ? 'mysql' : 'sqlite'
  const databaseUrl = isProduction
    ? `mysql://${encodeURIComponent(dbUser || 'root')}:${encodeURIComponent(dbPass || '')}@${dbHost || 'localhost'}:${dbPort || '3306'}/${dbName || 'realestateweb'}`
    : 'file:./dev.db'

  const jwtSecret = randomBytes(48).toString('hex')
  const resoTokenSecret = randomBytes(32).toString('hex')
  const resoSyncSecret = randomBytes(32).toString('hex')
  const automationSecret = randomBytes(32).toString('hex')

  // Build .env lines
  const envLines: string[] = [
    '# Generated by LuxeRealty Setup Wizard',
    `NODE_ENV=${isProduction ? 'production' : 'development'}`,
    `DB_PROVIDER=${dbProvider}`,
    `DATABASE_URL="${databaseUrl}"`,
    '',
    `JWT_SECRET=${jwtSecret}`,
    `JWT_EXPIRES_IN=7d`,
    '',
    `OPENAI_API_KEY=`,
    `ANTHROPIC_API_KEY=`,
    `OPENCLAW_WEBHOOK_SECRET=`,
    '',
    `NEXT_PUBLIC_APP_URL=${appUrl || 'http://localhost:3000'}`,
    `NEXT_PUBLIC_GOOGLE_MAPS_KEY=`,
    '',
    `RESO_API_BASE_URL=${isProduction ? '' : 'http://localhost:3000/api/mock-reso'}`,
    `RESO_CLIENT_ID=${isProduction ? '' : 'mock-client'}`,
    `RESO_CLIENT_SECRET=${isProduction ? '' : 'mock-secret'}`,
    `RESO_TOKEN_SECRET=${resoTokenSecret}`,
    `RESO_SYNC_SECRET=${resoSyncSecret}`,
    '',
    `AUTOMATION_PROCESS_SECRET=${automationSecret}`,
    `AUTOMATION_INTERVAL_MS=60000`,
  ]

  if (smtpHost) {
    envLines.push(
      '',
      `SMTP_HOST=${smtpHost}`,
      `SMTP_PORT=${smtpPort || '587'}`,
      `SMTP_USER=${smtpUser || ''}`,
      `SMTP_PASS=${smtpPass || ''}`,
      `SMTP_FROM=${smtpFrom || smtpUser || ''}`,
    )
  }

  if (twilioSid) {
    envLines.push(
      '',
      `TWILIO_ACCOUNT_SID=${twilioSid}`,
      `TWILIO_AUTH_TOKEN=${twilioToken || ''}`,
      `TWILIO_FROM_NUMBER=${twilioFrom || ''}`,
    )
  }

  fs.writeFileSync(ENV_PATH, envLines.join('\n') + '\n')

  // Update schema.prisma provider if switching to MySQL
  if (isProduction) {
    let schema = fs.readFileSync(SCHEMA_PATH, 'utf8')
    schema = schema.replace(
      /provider\s*=\s*"sqlite"/,
      'provider = "mysql"'
    )
    fs.writeFileSync(SCHEMA_PATH, schema)
  }

  // Run Prisma DB init
  const spawnEnv = {
    ...process.env,
    DATABASE_URL: databaseUrl,
    DB_PROVIDER: dbProvider,
  }

  try {
    if (dbProvider === 'sqlite') {
      execSync('npx prisma db push --skip-generate', { cwd: ROOT, env: spawnEnv, stdio: 'pipe', shell: true } as any)
    } else {
      execSync('npx prisma migrate deploy', { cwd: ROOT, env: spawnEnv, stdio: 'pipe', shell: true } as any)
    }
    execSync('npx prisma generate', { cwd: ROOT, env: spawnEnv, stdio: 'pipe', shell: true } as any)
  } catch (err: unknown) {
    const e = err as { stderr?: Buffer; message?: string }
    return NextResponse.json(
      {
        error: 'Database initialization failed. Check your connection details.',
        details: e.stderr?.toString() || e.message,
      },
      { status: 500 }
    )
  }

  // Write a temporary CJS script to create the admin user + seed stages
  const DEAL_STAGES = [
    { name: 'New Lead', order: 1, color: '#6366f1' },
    { name: 'Contacted', order: 2, color: '#8b5cf6' },
    { name: 'Showing', order: 3, color: '#f59e0b' },
    { name: 'Offer Made', order: 4, color: '#ef4444' },
    { name: 'Under Contract', order: 5, color: '#10b981' },
    { name: 'Closed', order: 6, color: '#059669' },
  ]

  const tempScript = path.join(ROOT, '.setup-admin-temp.cjs')
  fs.writeFileSync(
    tempScript,
    `
const { PrismaClient } = require('@prisma/client');
const bcrypt = require('bcryptjs');
const stages = ${JSON.stringify(DEAL_STAGES)};

async function main() {
  const prisma = new PrismaClient({
    datasourceUrl: process.env.DATABASE_URL,
  });
  try {
    const hash = await bcrypt.hash(process.env.ADMIN_PASS, 12);
    const existing = await prisma.user.findUnique({
      where: { email: process.env.ADMIN_EMAIL },
    });
    if (!existing) {
      await prisma.user.create({
        data: {
          name: process.env.ADMIN_NAME,
          email: process.env.ADMIN_EMAIL,
          passwordHash: hash,
          role: 'admin',
        },
      });
    }
    const stageCount = await prisma.stage.count();
    if (stageCount === 0) {
      for (const s of stages) {
        await prisma.stage.create({ data: s });
      }
    }
  } finally {
    await prisma.$disconnect();
  }
}

main().catch(e => { console.error(e); process.exit(1); });
`
  )

  try {
    execSync('node .setup-admin-temp.cjs', {
      cwd: ROOT,
      env: { ...spawnEnv, ADMIN_NAME: adminName, ADMIN_EMAIL: adminEmail, ADMIN_PASS: adminPassword },
      stdio: 'pipe',
      shell: true,
    } as any)
  } catch (err: unknown) {
    const e = err as { stderr?: Buffer; message?: string }
    return NextResponse.json(
      {
        error: 'Failed to create admin user.',
        details: e.stderr?.toString() || e.message,
      },
      { status: 500 }
    )
  } finally {
    try { fs.unlinkSync(tempScript) } catch { /* ignore */ }
  }

  return NextResponse.json({
    success: true,
    message: 'Setup complete. Restart the server to apply your configuration.',
  })
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { formatPrice } from '@/lib/utils'
import { Home, X, Plus, Eye, Link as LinkIcon } from 'lucide-react'

interface ResoPropertyInfo {
  id:           string
  listingKey:   string
  streetNumber: string | null
  streetName:   string | null
  unitNumber:   string | null
  city:         string
  listPrice:    number | null
  propertySubType: string | null
  media:        string | null
}

interface Interest {
  id:             string
  resoPropertyId: string
  source:         string
  notes:          string | null
  updatedAt:      string
  resoProperty:   ResoPropertyInfo
}

interface ViewRecord {
  property:  ResoPropertyInfo
  count:     number
  firstSeen: string
  lastSeen:  string
}

interface Summary {
  topType:   string
  minPrice:  number
  maxPrice:  number
  topCity:   string
}

interface Props { contactId: string }

function getAddress(p: ResoPropertyInfo): string {
  return [p.streetNumber, p.streetName].filter(Boolean).join(' ') || p.listingKey
}

export function PropertyInterestsPanel({ contactId }: Props) {
  const [tab,         setTab]         = useState<'interests' | 'history'>('interests')
  const [interests,   setInterests]   = useState<Interest[]>([])
  const [viewHistory, setViewHistory] = useState<ViewRecord[]>([])
  const [summary,     setSummary]     = useState<Summary | null>(null)
  const [loading,     setLoading]     = useState(true)
  const [showAdd,     setShowAdd]     = useState(false)
  const [searchQuery, setSearchQuery] = useState('')
  const [searchResults, setSearchResults] = useState<ResoPropertyInfo[]>([])
  const [searching,   setSearching]   = useState(false)

  const loadData = useCallback(async () => {
    setLoading(true)
    const res  = await fetch(`/api/contacts/${contactId}/property-interests`)
    const data = await res.json()
    setInterests(data.interests ?? [])
    setViewHistory(data.viewHistory ?? [])
    setSummary(data.summary ?? null)
    setLoading(false)
  }, [contactId])

  useEffect(() => { loadData() }, [loadData])

  async function searchListings(q: string) {
    if (!q.trim()) { setSearchResults([]); return }
    setSearching(true)
    const res  = await fetch(`/api/search?city=${encodeURIComponent(q)}&source=reso&pageSize=8`)
    const data = await res.json()
    setSearchResults((data.results ?? []).map((r: { id: string; listingKey?: string; address: string | null; city: string | null; price: number | null; propertyType: string | null; images: string[] }) => ({
      id:           r.id,
      listingKey:   r.listingKey ?? r.id,
      streetNumber: null,
      streetName:   r.address,
      unitNumber:   null,
      city:         r.city ?? '',
      listPrice:    r.price,
      propertySubType: r.propertyType,
      media:        r.images.length ? JSON.stringify(r.images.map((url, i) => ({ url, order: i + 1 }))) : null,
    })))
    setSearching(false)
  }

  async function addInterest(id: string) {
    await fetch(`/api/contacts/${contactId}/property-interests`, {
      method:  'POST',
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify({ resoPropertyId: id }),
    })
    setShowAdd(false)
    setSearchQuery('')
    setSearchResults([])
    loadData()
  }

  async function removeInterest(resoPropertyId: string) {
    await fetch(`/api/contacts/${contactId}/property-interests/${resoPropertyId}`, { method: 'DELETE' })
    loadData()
  }

  function formatDate(iso: string) {
    return new Date(iso).toLocaleDateString('en-CA', { month: 'short', day: 'numeric', year: 'numeric' })
  }

  const getFirstImage = (media: string | null): string => {
    try {
      const items = JSON.parse(media ?? '[]') as { url: string }[]
      return items[0]?.url ?? '/placeholder-property.jpg'
    }
    catch { return '/placeholder-property.jpg' }
  }

  return (
    <div className="rounded-xl border border-charcoal-100 overflow-hidden">
      {/* Summary header */}
      <div className="bg-charcoal-50 px-5 py-4 border-b border-charcoal-100">
        <h3 className="font-semibold text-charcoal-900 mb-1">Property Interests</h3>
        {summary ? (
          <p className="text-sm text-charcoal-500">
            Mostly viewing: <strong className="text-charcoal-700 capitalize">{summary.topType}</strong>
            {' ┬╖ '}
            <strong className="text-charcoal-700">{formatPrice(summary.minPrice)}ΓÇô{formatPrice(summary.maxPrice)}</strong>
            {' ┬╖ '}
            <strong className="text-charcoal-700">{summary.topCity}</strong>
          </p>
        ) : (
          <p className="text-sm text-charcoal-400">No browsing data yet</p>
        )}
      </div>

      {/* Tabs */}
      <div className="flex border-b border-charcoal-100">
        {(['interests', 'history'] as const).map(t => (
          <button
            key={t}
            onClick={() => setTab(t)}
            className={`flex-1 py-2.5 text-sm font-medium capitalize transition-colors ${
              tab === t
                ? 'border-b-2 border-gold-500 text-gold-600'
                : 'text-charcoal-400 hover:text-charcoal-700'
            }`}
          >
            {t === 'interests' ? `Interests (${interests.length})` : `View History (${viewHistory.length})`}
          </button>
        ))}
      </div>

      {/* Content */}
      <div className="p-4">
        {loading ? (
          <p className="text-sm text-charcoal-400 text-center py-6">LoadingΓÇª</p>
        ) : tab === 'interests' ? (
          <>
            <button
              onClick={() => setShowAdd(s => !s)}
              className="flex items-center gap-1.5 text-sm text-gold-600 hover:text-gold-700 mb-3 font-medium"
            >
              <Plus size={15} /> Add listing
            </button>

            {showAdd && (
              <div className="mb-4 rounded-lg border border-charcoal-200 p-3">
                <input
                  autoFocus
                  placeholder="Search listingsΓÇª"
                  value={searchQuery}
                  onChange={e => { setSearchQuery(e.target.value); searchListings(e.target.value) }}
                  className="w-full text-sm border border-charcoal-200 rounded-lg px-3 py-2 mb-2 focus:outline-none focus:ring-2 focus:ring-gold-500"
                />
                {searching && <p className="text-xs text-charcoal-400">SearchingΓÇª</p>}
                {searchResults.map(p => (
                  <button
                    key={p.id}
                    onClick={() => addInterest(p.id)}
                    className="flex items-start gap-2 w-full text-left rounded-lg hover:bg-charcoal-50 px-2 py-1.5 text-sm"
                  >
                    <Home size={14} className="shrink-0 text-charcoal-400 mt-0.5" />
                    <div>
                      <p className="text-charcoal-800 font-medium leading-tight">{getAddress(p)}, {p.city}</p>
                      <p className="text-charcoal-400 text-xs">{formatPrice(p.listPrice ?? 0)} ┬╖ {p.propertySubType}</p>
                    </div>
                  </button>
                ))}
              </div>
            )}

            {interests.length === 0 ? (
              <p className="text-sm text-charcoal-400 text-center py-4">No interests recorded yet</p>
            ) : (
              <div className="flex flex-col gap-2">
                {interests.map(i => (
                  <div key={i.id} className="flex items-start gap-3 rounded-lg bg-charcoal-50 px-3 py-2.5">
                    <img
                      src={getFirstImage(i.resoProperty.media)}
                      alt={getAddress(i.resoProperty)}
                      className="h-12 w-16 rounded-md object-cover shrink-0"
                    />
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-medium text-charcoal-900 truncate">{getAddress(i.resoProperty)}, {i.resoProperty.city}</p>
                      <p className="text-xs text-charcoal-500">{formatPrice(i.resoProperty.listPrice ?? 0)} ┬╖ <span className="capitalize">{i.resoProperty.propertySubType}</span></p>
                      <div className="flex items-center gap-2 mt-1">
                        <span className={`inline-flex items-center gap-1 text-xs px-1.5 py-0.5 rounded-full font-medium ${
                          i.source === 'auto'
                            ? 'bg-blue-50 text-blue-600'
                            : 'bg-gold-50 text-gold-700'
                        }`}>
                          {i.source === 'auto' ? <Eye size={10} /> : <LinkIcon size={10} />}
                          {i.source === 'auto' ? 'Viewed' : 'Linked'}
                        </span>
                        <span className="text-xs text-charcoal-400">{formatDate(i.updatedAt)}</span>
                      </div>
                    </div>
                    <button
                      onClick={() => removeInterest(i.resoPropertyId)}
                      className="shrink-0 text-charcoal-300 hover:text-red-500 transition-colors mt-0.5"
                    >
                      <X size={14} />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </>
        ) : (
          /* View History tab */
          viewHistory.length === 0 ? (
            <p className="text-sm text-charcoal-400 text-center py-4">No view history yet</p>
          ) : (
            <div className="flex flex-col gap-2">
              {viewHistory.map(v => (
                <div key={v.property.id} className="flex items-start gap-3 rounded-lg bg-charcoal-50 px-3 py-2.5">
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-charcoal-900 truncate">{getAddress(v.property)}, {v.property.city}</p>
                    <p className="text-xs text-charcoal-500">{formatPrice(v.property.listPrice ?? 0)} ┬╖ <span className="capitalize">{v.property.propertySubType}</span></p>
                  </div>
                  <div className="text-right shrink-0">
                    <p className="text-xs font-semibold text-charcoal-700">{v.count} view{v.count !== 1 ? 's' : ''}</p>
                    <p className="text-xs text-charcoal-400">Last: {formatDate(v.lastSeen)}</p>
                  </div>
                </div>
              ))}
            </div>
          )
        )}
      </div>
    </div>
  )
}

'use client'

import { motion } from 'framer-motion'
import { TrendingUp, TrendingDown } from 'lucide-react'
import { Card } from '@/components/layout'
import { cn } from '@/lib/utils'

interface StatsCardProps {
  title: string
  value: string | number
  change?: number
  changeLabel?: string
  icon?: React.ReactNode
  className?: string
}

export function StatsCard({ title, value, change, changeLabel, icon, className }: StatsCardProps) {
  const positive = change != null && change >= 0
  return (
    <Card className={cn('', className)}>
      <div className="flex items-start justify-between">
        <div>
          <p className="text-sm text-charcoal-500 font-medium">{title}</p>
          <p className="mt-1 text-3xl font-bold text-charcoal-900 font-serif">{value}</p>
          {change != null && (
            <div className={cn('flex items-center gap-1 mt-2 text-xs font-medium', positive ? 'text-emerald-600' : 'text-red-500')}>
              {positive ? <TrendingUp size={12} /> : <TrendingDown size={12} />}
              {Math.abs(change)}% {changeLabel ?? 'vs last month'}
            </div>
          )}
        </div>
        {icon && (
          <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-charcoal-100 text-charcoal-600">
            {icon}
          </div>
        )}
      </div>
    </Card>
  )
}

'use client'

/**
 * CampaignBuilder
 *
 * Modal-style form for creating or editing a drip campaign with a variable
 * number of steps. Each step defines channel, delay (minutes or days), and content.
 */

import { useState, useRef } from 'react'
import { Plus, Trash2, ChevronUp, ChevronDown, Zap, Save, Paperclip, X } from 'lucide-react'
import { Button } from '@/components/ui'
import { MergeTagPicker } from './MergeTagPicker'

type StepType    = 'send_email' | 'send_sms' | 'create_task' | 'wait' | 'update_lead_score' | 'transfer_campaign'
type TriggerType = 'new_lead' | 'deal_stage_change' | 'showing_scheduled' | 'manual'
type DelayUnit   = 'minutes' | 'days'

interface CampaignSummary {
  id:    string
  name:  string
  steps: Array<{ order: number; type: string }>
}

interface StepForm {
  order:        number
  type:         StepType
  delayMinutes: number
  delayUnit:    DelayUnit
  config:       Record<string, string | number>
}

interface InitialCampaignData {
  name:        string
  description: string
  trigger:     TriggerType
  steps: Array<{
    order:        number
    type:         StepType
    delayMinutes: number
    config:       Record<string, string | number>
  }>
}

interface CampaignBuilderProps {
  /** Called after a successful create */
  onCreated?:        () => void
  /** Called after a successful update (edit mode) */
  onUpdated?:        () => void
  /** When provided, the form operates in edit mode */
  campaignId?:       string
  /** Pre-filled data for edit mode */
  initialData?:      InitialCampaignData
  /** All campaigns available for transfer steps (should exclude self) */
  allCampaigns?:     CampaignSummary[]
  /** Id of the campaign being edited ΓÇö used to exclude self from transfer targets */
  currentCampaignId?: string
}

const STEP_LABELS: Record<StepType, string> = {
  send_email:         'Send Email',
  send_sms:           'Send SMS',
  create_task:        'Call',
  wait:               'Wait / Delay',
  update_lead_score:  'Update Lead Score',
  transfer_campaign:  'Transfer to Campaign',
}

const TRIGGER_LABELS: Record<TriggerType, string> = {
  new_lead:           'New Lead Created',
  deal_stage_change:  'Deal Stage Changed',
  showing_scheduled:  'Showing Scheduled',
  manual:             'Manual Enrollment',
}

function defaultConfig(type: StepType): Record<string, string | number> {
  switch (type) {
    case 'send_email':        return { subject: '', body: '' }
    case 'send_sms':          return { body: '' }
    case 'create_task':       return { title: '', priority: 'normal' }
    case 'wait':              return {}
    case 'update_lead_score': return { delta: 5 }
    case 'transfer_campaign': return { targetSequenceId: '', targetSequenceName: '', startAtStep: 0 }
  }
}

/** Infer a sensible display unit from a delayMinutes value */
function inferUnit(delayMinutes: number): DelayUnit {
  return delayMinutes > 0 && delayMinutes % 1440 === 0 ? 'days' : 'minutes'
}

function initialStepForm(s: InitialCampaignData['steps'][number]): StepForm {
  return {
    order:        s.order,
    type:         s.type,
    delayMinutes: s.delayMinutes,
    delayUnit:    inferUnit(s.delayMinutes),
    config:       s.config,
  }
}

export function CampaignBuilder({ onCreated, onUpdated, campaignId, initialData, allCampaigns, currentCampaignId }: CampaignBuilderProps) {
  const isEditMode = Boolean(campaignId)

  const [name,        setName]        = useState(initialData?.name        ?? '')
  const [description, setDescription] = useState(initialData?.description ?? '')
  const [trigger,     setTrigger]     = useState<TriggerType>(initialData?.trigger ?? 'new_lead')
  const [steps,       setSteps]       = useState<StepForm[]>(
    initialData?.steps?.length
      ? initialData.steps.map(initialStepForm)
      : [{ order: 0, type: 'send_email', delayMinutes: 0, delayUnit: 'minutes', config: defaultConfig('send_email') }]
  )
  const [saving, setSaving] = useState(false)
  const [error,  setError]  = useState('')

  function addStep() {
    setSteps(prev => [
      ...prev,
      { order: prev.length, type: 'send_email', delayMinutes: 1440, delayUnit: 'days', config: defaultConfig('send_email') },
    ])
  }

  function removeStep(index: number) {
    setSteps(prev => prev.filter((_, i) => i !== index).map((s, i) => ({ ...s, order: i })))
  }

  function moveStep(index: number, dir: -1 | 1) {
    const next = [...steps]
    const swap = index + dir
    if (swap < 0 || swap >= next.length) return
    ;[next[index], next[swap]] = [next[swap], next[index]]
    setSteps(next.map((s, i) => ({ ...s, order: i })))
  }

  function updateStep(index: number, patch: Partial<StepForm>) {
    setSteps(prev => prev.map((s, i) => {
      if (i !== index) return s
      const updated = { ...s, ...patch }
      // Reset config when type changes
      if (patch.type && patch.type !== s.type) updated.config = defaultConfig(patch.type)
      return updated
    }))
  }

  function updateConfig(index: number, key: string, value: string | number) {
    setSteps(prev => prev.map((s, i) =>
      i === index ? { ...s, config: { ...s.config, [key]: value } } : s,
    ))
  }

  /** Returns the display value for the delay input given current unit */
  function displayDelay(step: StepForm): number {
    return step.delayUnit === 'days' ? Math.round(step.delayMinutes / 1440) : step.delayMinutes
  }

  function handleDelayChange(index: number, rawValue: string) {
    const val = parseInt(rawValue) || 0
    const step = steps[index]
    updateStep(index, { delayMinutes: step.delayUnit === 'days' ? val * 1440 : val })
  }

  function handleUnitChange(index: number, unit: DelayUnit) {
    // Keep the delayMinutes value as-is; only the display unit changes
    updateStep(index, { delayUnit: unit })
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    if (!name.trim()) { setError('Name is required'); return }
    setSaving(true)
    setError('')
    try {
      // Strip delayUnit (UI-only) before sending to API
      const apiSteps = steps.map(({ delayUnit: _u, ...s }) => s)

      const url    = isEditMode ? `/api/campaigns/${campaignId}` : '/api/campaigns'
      const method = isEditMode ? 'PATCH' : 'POST'

      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ name, description, trigger, steps: apiSteps }),
      })
      if (!res.ok) {
        let message = `Failed to ${isEditMode ? 'update' : 'create'} campaign`
        try {
          const json = await res.json()
          if (json.error) message = typeof json.error === 'string' ? json.error : JSON.stringify(json.error)
        } catch { /* response body was empty or not JSON */ }
        throw new Error(message)
      }
      if (isEditMode) {
        onUpdated?.()
      } else {
        onCreated?.()
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : `Failed to ${isEditMode ? 'update' : 'create'} campaign`)
    } finally {
      setSaving(false)
    }
  }

  return (
    <form onSubmit={handleSubmit} className="flex flex-col gap-5">
      {/* Campaign metadata */}
      <div className="grid grid-cols-2 gap-4">
        <div className="col-span-2">
          <label className="text-xs text-charcoal-500 mb-1 block">Campaign Name *</label>
          <input type="text" value={name} onChange={e => setName(e.target.value)}
            placeholder="e.g. New Buyer Welcome Series"
            className="w-full rounded-lg border border-charcoal-200 bg-white px-3 py-2 text-sm text-charcoal-900 placeholder:text-charcoal-400 focus:outline-none focus:ring-2 focus:ring-charcoal-900"
          />
        </div>
        <div>
          <label className="text-xs text-charcoal-500 mb-1 block">Trigger</label>
          <select value={trigger} onChange={e => setTrigger(e.target.value as TriggerType)}
            className="w-full rounded-lg border border-charcoal-200 bg-white px-3 py-1.5 text-sm text-charcoal-900 focus:outline-none focus:ring-2 focus:ring-charcoal-900">
            {Object.entries(TRIGGER_LABELS).map(([v, l]) => (
              <option key={v} value={v}>{l}</option>
            ))}
          </select>
        </div>
        <div>
          <label className="text-xs text-charcoal-500 mb-1 block">Description (optional)</label>
          <input type="text" value={description} onChange={e => setDescription(e.target.value)}
            placeholder="Brief description"
            className="w-full rounded-lg border border-charcoal-200 bg-white px-3 py-2 text-sm text-charcoal-900 placeholder:text-charcoal-400 focus:outline-none focus:ring-2 focus:ring-charcoal-900"
          />
        </div>
      </div>

      {/* Steps */}
      <div>
        <div className="flex items-center justify-between mb-2">
          <p className="text-xs font-semibold text-charcoal-700 uppercase tracking-wide">Steps</p>
          <button type="button" onClick={addStep}
            className="flex items-center gap-1 text-xs text-gold-600 hover:text-gold-700 font-medium">
            <Plus size={12} /> Add Step
          </button>
        </div>

        <div className="flex flex-col gap-3">
          {steps.map((step, i) => (
            <div key={i} className="rounded-xl border border-charcoal-200 bg-charcoal-50 p-3">
              <div className="flex items-center gap-2 mb-3">
                <span className="flex h-5 w-5 items-center justify-center rounded-full bg-charcoal-200 text-xs font-bold text-charcoal-700">
                  {i + 1}
                </span>
                <select value={step.type}
                  onChange={e => updateStep(i, { type: e.target.value as StepType })}
                  className="flex-1 rounded-lg border border-charcoal-200 bg-white px-2 py-1 text-sm text-charcoal-900 focus:outline-none focus:ring-2 focus:ring-charcoal-900">
                  {Object.entries(STEP_LABELS).map(([v, l]) => (
                    <option key={v} value={v}>{l}</option>
                  ))}
                </select>
                <div className="flex items-center gap-1 shrink-0">
                  <button type="button" onClick={() => moveStep(i, -1)} disabled={i === 0}
                    className="text-charcoal-400 hover:text-charcoal-700 disabled:opacity-30">
                    <ChevronUp size={14} />
                  </button>
                  <button type="button" onClick={() => moveStep(i, 1)} disabled={i === steps.length - 1}
                    className="text-charcoal-400 hover:text-charcoal-700 disabled:opacity-30">
                    <ChevronDown size={14} />
                  </button>
                  <button type="button" onClick={() => removeStep(i)}
                    className="text-red-400 hover:text-red-600 ml-1">
                    <Trash2 size={14} />
                  </button>
                </div>
              </div>

              {/* Delay with unit selector */}
              <div className="flex items-center gap-2 mb-2">
                <label className="text-xs text-charcoal-500 shrink-0">Wait</label>
                <input
                  type="number" min={0}
                  value={displayDelay(step)}
                  onChange={e => handleDelayChange(i, e.target.value)}
                  className="w-20 rounded border border-charcoal-200 bg-white px-2 py-1 text-sm text-charcoal-900 focus:outline-none focus:ring-2 focus:ring-charcoal-900"
                />
                <select
                  value={step.delayUnit}
                  onChange={e => handleUnitChange(i, e.target.value as DelayUnit)}
                  className="rounded border border-charcoal-200 bg-white px-2 py-1 text-sm text-charcoal-900 focus:outline-none focus:ring-2 focus:ring-charcoal-900">
                  <option value="minutes">minutes</option>
                  <option value="days">days</option>
                </select>
                <span className="text-xs text-charcoal-400">before this step</span>
              </div>

              {/* Step-type-specific config */}
              <StepConfig
                type={step.type}
                config={step.config}
                onChange={(k, v) => updateConfig(i, k, v)}
                allCampaigns={allCampaigns}
                currentCampaignId={campaignId ?? currentCampaignId}
              />
            </div>
          ))}
        </div>
      </div>

      {error && <p className="text-xs text-red-600">{error}</p>}

      <Button type="submit" variant="primary" loading={saving}
        leftIcon={isEditMode ? <Save size={14} /> : <Zap size={14} />}>
        {isEditMode ? 'Save Changes' : 'Create Campaign'}
      </Button>
    </form>
  )
}

function StepConfig({ type, config, onChange, allCampaigns, currentCampaignId }: {
  type:               StepType
  config:             Record<string, string | number>
  onChange:           (key: string, value: string | number) => void
  allCampaigns?:      CampaignSummary[]
  currentCampaignId?: string
}) {
  const [uploading, setUploading]     = useState(false)
  const [uploadError, setUploadError] = useState('')
  const fileInputRef = useRef<HTMLInputElement>(null)
  const bodyRef      = useRef<HTMLTextAreaElement>(null)
  const inputCls = 'w-full rounded-lg border border-charcoal-200 bg-white px-2 py-1 text-sm text-charcoal-900 placeholder:text-charcoal-400 focus:outline-none focus:ring-2 focus:ring-charcoal-900'

  async function handleAttachmentPick(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0]
    if (!file) return
    setUploading(true)
    setUploadError('')
    try {
      const fd = new FormData()
      fd.append('file', file)
      const res = await fetch('/api/uploads', { method: 'POST', body: fd })
      if (!res.ok) {
        const json = await res.json().catch(() => ({}))
        throw new Error((json as { error?: string }).error ?? 'Upload failed')
      }
      const { data } = await res.json()
      onChange('attachmentUrl',  data.url)
      onChange('attachmentName', data.originalName)
    } catch (err) {
      setUploadError(err instanceof Error ? err.message : 'Upload failed')
    } finally {
      setUploading(false)
      e.target.value = ''
    }
  }

  function clearAttachment() {
    onChange('attachmentUrl',  '')
    onChange('attachmentName', '')
  }

  switch (type) {
    case 'send_email':
      return (
        <div className="flex flex-col gap-2">
          <input type="text" placeholder="Email subject" value={config.subject as string}
            onChange={e => onChange('subject', e.target.value)} className={inputCls} />
          <MergeTagPicker textareaRef={bodyRef} value={config.body as string} onChange={v => onChange('body', v)} />
          <textarea ref={bodyRef} placeholder="Email body (HTML allowed)" rows={3} value={config.body as string}
            onChange={e => onChange('body', e.target.value)}
            className={`${inputCls} resize-none font-mono`} />

          {/* Attachment */}
          <input ref={fileInputRef} type="file" className="hidden" onChange={handleAttachmentPick} />
          {uploadError && <p className="text-xs text-red-500">{uploadError}</p>}
          {config.attachmentName ? (
            <div className="flex items-center gap-2 text-xs text-charcoal-700">
              <Paperclip size={11} className="text-charcoal-400 shrink-0" />
              <span className="truncate flex-1">{config.attachmentName as string}</span>
              <button type="button" onClick={clearAttachment} className="text-charcoal-400 hover:text-red-500 transition-colors">
                <X size={12} />
              </button>
            </div>
          ) : (
            <button
              type="button"
              disabled={uploading}
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center gap-1.5 text-xs text-charcoal-500 hover:text-charcoal-800 transition-colors disabled:opacity-50"
            >
              <Paperclip size={13} />
              {uploading ? 'UploadingΓÇª' : 'Attach a file'}
            </button>
          )}
        </div>
      )
    case 'send_sms':
      return (
        <textarea placeholder="SMS message (max 160 chars)" rows={2} value={config.body as string}
          onChange={e => onChange('body', e.target.value)}
          className={`${inputCls} resize-none`} maxLength={160} />
      )
    case 'create_task':
      return (
        <div className="flex gap-2">
          <input type="text" placeholder="Task title" value={config.title as string}
            onChange={e => onChange('title', e.target.value)} className={`${inputCls} flex-1`} />
          <select value={config.priority as string} onChange={e => onChange('priority', e.target.value)}
            className={`${inputCls} w-28`}>
            {['low', 'normal', 'high', 'urgent'].map(p => <option key={p} value={p}>{p}</option>)}
          </select>
        </div>
      )
    case 'update_lead_score':
      return (
        <div className="flex items-center gap-2">
          <label className="text-xs text-charcoal-500 shrink-0">Score delta</label>
          <input type="number" value={config.delta as number}
            onChange={e => onChange('delta', parseInt(e.target.value) || 0)}
            className={`${inputCls} w-24`} />
          <span className="text-xs text-charcoal-400">(use negative to deduct)</span>
        </div>
      )
    case 'wait':
      return <p className="text-xs text-charcoal-400">This step pauses the sequence for the delay above.</p>

    case 'transfer_campaign': {
      const available = (allCampaigns ?? []).filter(c => c.id !== currentCampaignId)
      const selected  = available.find(c => c.id === (config.targetSequenceId as string))
      return (
        <div className="flex flex-col gap-2">
          {available.length === 0 ? (
            <p className="text-xs text-charcoal-400 italic">No other campaigns exist yet. Create another campaign first.</p>
          ) : (
            <>
              <select
                value={config.targetSequenceId as string}
                onChange={e => {
                  const target = available.find(c => c.id === e.target.value)
                  onChange('targetSequenceId',  e.target.value)
                  onChange('targetSequenceName', target?.name ?? '')
                  onChange('startAtStep', 0)
                }}
                className={inputCls}
              >
                <option value="">ΓÇö Select target campaign ΓÇö</option>
                {available.map(c => (
                  <option key={c.id} value={c.id}>{c.name}</option>
                ))}
              </select>

              {selected && selected.steps.length > 0 && (
                <div className="flex items-center gap-2">
                  <label className="text-xs text-charcoal-500 shrink-0">Start at step</label>
                  <select
                    value={config.startAtStep as number}
                    onChange={e => onChange('startAtStep', parseInt(e.target.value))}
                    className={`${inputCls} w-auto`}
                  >
                    {selected.steps.map((s, idx) => (
                      <option key={idx} value={idx}>
                        Step {idx + 1} ΓÇö {STEP_LABELS[s.type as StepType] ?? s.type}
                      </option>
                    ))}
                  </select>
                </div>
              )}

              {selected && (
                <p className="text-xs text-charcoal-400">
                  Contact will be moved out of this campaign and enrolled in &quot;{selected.name}&quot;.
                </p>
              )}
            </>
          )}
        </div>
      )
    }

    default:
      return null
  }
}

'use client'

/**
 * CampaignEnrollmentsModal
 *
 * Opens a paginated table of all enrollments for a campaign.
 * Supports Pause, Resume, and Unenroll actions per row.
 */

import { useState, useEffect } from 'react'
import { Users } from 'lucide-react'
import { Modal, Badge, Button } from '@/components/ui'
import { formatDate } from '@/lib/utils'

type EnrollmentStatus = 'active' | 'paused' | 'completed' | 'cancelled'

type EnrollmentRow = {
  id:          string
  status:      EnrollmentStatus
  currentStep: number
  nextRunAt:   string | null
  enrolledAt:  string
  completedAt: string | null
  contact: {
    id:        string
    firstName: string
    lastName:  string
    email:     string | null
  }
}

interface Props {
  open:         boolean
  onClose:      () => void
  campaignId:   string
  campaignName: string
  totalSteps:   number
}

const STATUS_CONFIG: Record<EnrollmentStatus, { label: string; variant: 'success' | 'gold' | 'info' | 'default' }> = {
  active:    { label: 'Active',     variant: 'success' },
  paused:    { label: 'Paused',     variant: 'gold'    },
  completed: { label: 'Completed',  variant: 'info'    },
  cancelled: { label: 'Unenrolled', variant: 'default' },
}

const PAGE_SIZE = 25

export function CampaignEnrollmentsModal({ open, onClose, campaignId, campaignName, totalSteps }: Props) {
  const [rows,       setRows]       = useState<EnrollmentRow[]>([])
  const [total,      setTotal]      = useState(0)
  const [totalPages, setTotalPages] = useState(1)
  const [page,       setPage]       = useState(1)
  const [loading,    setLoading]    = useState(false)
  const [error,      setError]      = useState('')

  useEffect(() => {
    if (!open) return
    setPage(1)
    fetchPage(1)
  }, [open, campaignId])

  async function fetchPage(p: number) {
    setLoading(true)
    setError('')
    try {
      const res  = await fetch(`/api/campaigns/${campaignId}/enrollments?page=${p}&pageSize=${PAGE_SIZE}`)
      const json = await res.json()
      if (!res.ok) throw new Error(json.error ?? 'Failed to load enrollments')
      setRows(json.data)
      setTotal(json.total)
      setTotalPages(json.totalPages)
      setPage(p)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load enrollments')
    } finally {
      setLoading(false)
    }
  }

  async function updateStatus(enrollmentId: string, status: 'active' | 'paused' | 'cancelled' | 'restart') {
    setError('')
    try {
      const res  = await fetch(`/api/campaigns/enrollments/${enrollmentId}`, {
        method:  'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ status }),
      })
      const json = await res.json()
      if (!res.ok) throw new Error(json.error ?? 'Failed to update enrollment')
      const optimisticStatus = status === 'restart' ? 'active' : status
      setRows(prev => prev.map(r => r.id === enrollmentId ? { ...r, status: optimisticStatus } : r))
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to update enrollment')
    }
  }

  return (
    <Modal open={open} onClose={onClose} title={campaignName} size="xl">
      <div className="flex flex-col gap-4">

        {/* Count */}
        <p className="text-sm text-charcoal-500 flex items-center gap-1.5">
          <Users size={14} />
          {loading ? 'LoadingΓÇª' : `${total} enrollment${total !== 1 ? 's' : ''}`}
        </p>

        {error && <p className="text-xs text-red-600">{error}</p>}

        {/* Table */}
        {!loading && rows.length === 0 && !error && (
          <p className="text-sm text-charcoal-400 text-center py-10">No enrollments yet.</p>
        )}

        {rows.length > 0 && (
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-charcoal-100 text-xs text-charcoal-500 uppercase tracking-wide">
                  <th className="pb-2 text-left font-medium">Contact</th>
                  <th className="pb-2 text-left font-medium">Step</th>
                  <th className="pb-2 text-left font-medium">Status</th>
                  <th className="pb-2 text-left font-medium">Next run</th>
                  <th className="pb-2 text-right font-medium">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-charcoal-50">
                {rows.map(row => {
                  const cfg = STATUS_CONFIG[row.status]
                  return (
                    <tr key={row.id} className="hover:bg-charcoal-50 transition-colors">
                      <td className="py-2.5 pr-4">
                        <p className="font-medium text-charcoal-900">
                          {row.contact.firstName} {row.contact.lastName}
                        </p>
                        {row.contact.email && (
                          <p className="text-xs text-charcoal-400">{row.contact.email}</p>
                        )}
                      </td>
                      <td className="py-2.5 pr-4 text-charcoal-600 whitespace-nowrap">
                        {row.currentStep + 1} of {totalSteps}
                      </td>
                      <td className="py-2.5 pr-4">
                        <Badge variant={cfg.variant} className="text-xs">{cfg.label}</Badge>
                      </td>
                      <td className="py-2.5 pr-4 text-xs text-charcoal-500 whitespace-nowrap">
                        {row.nextRunAt
                          ? formatDate(new Date(row.nextRunAt), { month: 'short', day: 'numeric' })
                          : 'ΓÇö'
                        }
                      </td>
                      <td className="py-2.5 text-right">
                        <div className="flex items-center justify-end gap-1">
                          {row.status === 'active' && (
                            <>
                              <button
                                onClick={() => updateStatus(row.id, 'paused')}
                                className="rounded px-2 py-1 text-xs text-charcoal-500 hover:bg-charcoal-100 transition-colors">
                                Pause
                              </button>
                              <button
                                onClick={() => updateStatus(row.id, 'cancelled')}
                                className="rounded px-2 py-1 text-xs text-red-500 hover:bg-red-50 transition-colors">
                                Unenroll
                              </button>
                            </>
                          )}
                          {row.status === 'paused' && (
                            <>
                              <button
                                onClick={() => updateStatus(row.id, 'active')}
                                className="rounded px-2 py-1 text-xs text-green-600 hover:bg-green-50 transition-colors">
                                Resume
                              </button>
                              <button
                                onClick={() => updateStatus(row.id, 'cancelled')}
                                className="rounded px-2 py-1 text-xs text-red-500 hover:bg-red-50 transition-colors">
                                Unenroll
                              </button>
                            </>
                          )}
                          {row.status === 'completed' && (
                            <>
                              <button
                                onClick={() => updateStatus(row.id, 'restart')}
                                className="rounded px-2 py-1 text-xs text-green-600 hover:bg-green-50 transition-colors">
                                Restart
                              </button>
                              <button
                                onClick={() => updateStatus(row.id, 'cancelled')}
                                className="rounded px-2 py-1 text-xs text-red-500 hover:bg-red-50 transition-colors">
                                Remove
                              </button>
                            </>
                          )}
                        </div>
                      </td>
                    </tr>
                  )
                })}
              </tbody>
            </table>
          </div>
        )}

        {/* Pagination */}
        {totalPages > 1 && (
          <div className="flex items-center justify-between pt-2 border-t border-charcoal-100">
            <p className="text-xs text-charcoal-400">
              Page {page} of {totalPages}
            </p>
            <div className="flex gap-2">
              <Button
                variant="ghost" size="sm"
                disabled={page <= 1}
                onClick={() => fetchPage(page - 1)}>
                Previous
              </Button>
              <Button
                variant="ghost" size="sm"
                disabled={page >= totalPages}
                onClick={() => fetchPage(page + 1)}>
                Next
              </Button>
            </div>
          </div>
        )}

      </div>
    </Modal>
  )
}

'use client'

/**
 * SpecialEventBuilder
 *
 * Creates / edits a "special_event" campaign where each step fires on a
 * date anchored to a contact-specific event:
 *
 *   ΓÇó Contact's Birthday           ΓÇö annual, e.g. 7 days before
 *   ΓÇó Anniversary of Last Deal     ΓÇö annual, on the closing anniversary
 *   ΓÇó Fixed Calendar Date          ΓÇö annual, e.g. Dec 25 (Christmas)
 *
 * Steps are NOT sequential delays ΓÇö each step has its own independent
 * date anchor and offset.  delayMinutes is stored as 0 and ignored.
 */

import { useState, useRef } from 'react'
import { Plus, Trash2, Save, Star, Paperclip, X } from 'lucide-react'
import { Button } from '@/components/ui'
import { MergeTagPicker } from './MergeTagPicker'

// ΓöÇΓöÇ Types ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

type ActionType    = 'send_email' | 'send_sms' | 'create_task' | 'update_lead_score'
type ScheduleType  = 'contact_birthday' | 'last_deal_closed' | 'fixed_date'

interface EventStep {
  order:        number
  type:         ActionType
  scheduleType: ScheduleType
  offsetDays:   number         // negative = before, positive = after, 0 = on the day
  fixedMonth:   number         // 1-12, only relevant for fixed_date
  fixedDay:     number         // 1-31, only relevant for fixed_date
  config:       Record<string, string | number>
}

interface InitialData {
  name:        string
  description: string
  steps: Array<{
    order:        number
    type:         ActionType
    delayMinutes: number
    config:       Record<string, string | number>
  }>
}

interface Props {
  onCreated?:  () => void
  onUpdated?:  () => void
  campaignId?: string
  initialData?: InitialData
}

// ΓöÇΓöÇ Constants ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const ACTION_LABELS: Record<ActionType, string> = {
  send_email:        'Send Email',
  send_sms:          'Send SMS',
  create_task:       'Call',
  update_lead_score: 'Update Lead Score',
}

const SCHEDULE_LABELS: Record<ScheduleType, string> = {
  contact_birthday: "Contact's Birthday",
  last_deal_closed: 'Anniversary of Last Closed Deal',
  fixed_date:       'Fixed Calendar Date',
}

const MONTHS = [
  'January','February','March','April','May','June',
  'July','August','September','October','November','December',
]

function daysInMonth(month: number): number {
  // month is 1-indexed; use a non-leap year for simplicity
  return new Date(2001, month, 0).getDate()
}

function defaultConfig(type: ActionType): Record<string, string | number> {
  switch (type) {
    case 'send_email':        return { subject: '', body: '' }
    case 'send_sms':          return { body: '' }
    case 'create_task':       return { title: '', priority: 'normal' }
    case 'update_lead_score': return { delta: 5 }
  }
}

function parseExistingStep(s: InitialData['steps'][number]): EventStep {
  const cfg = s.config as Record<string, unknown>
  return {
    order:        s.order,
    type:         s.type as ActionType,
    scheduleType: (cfg.scheduleType as ScheduleType) ?? 'contact_birthday',
    offsetDays:   (cfg.offsetDays   as number) ?? 0,
    fixedMonth:   (cfg.fixedMonth   as number) ?? 12,
    fixedDay:     (cfg.fixedDay     as number) ?? 25,
    config:       s.config,
  }
}

function emptyStep(order: number): EventStep {
  return {
    order,
    type:         'send_email',
    scheduleType: 'contact_birthday',
    offsetDays:   0,
    fixedMonth:   12,
    fixedDay:     25,
    config:       defaultConfig('send_email'),
  }
}

// ΓöÇΓöÇ Step action config inputs (same style as CampaignBuilder) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function StepActionConfig({
  step, onChange, onConfigChange,
}: {
  step:           EventStep
  onChange:       (patch: Partial<EventStep>) => void
  onConfigChange: (key: string, value: string | number) => void
}) {
  const [uploading, setUploading]     = useState(false)
  const [uploadError, setUploadError] = useState('')
  const fileRef = useRef<HTMLInputElement>(null)
  const bodyRef = useRef<HTMLTextAreaElement>(null)

  const inputCls = 'w-full rounded-lg border border-charcoal-200 bg-white px-2 py-1 text-sm text-charcoal-900 placeholder:text-charcoal-400 focus:outline-none focus:ring-2 focus:ring-charcoal-900'

  async function handleAttachment(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0]
    if (!file) return
    setUploading(true); setUploadError('')
    try {
      const fd = new FormData(); fd.append('file', file)
      const res = await fetch('/api/uploads', { method: 'POST', body: fd })
      if (!res.ok) throw new Error((await res.json().catch(() => ({}))).error ?? 'Upload failed')
      const { data } = await res.json()
      onConfigChange('attachmentUrl',  data.url)
      onConfigChange('attachmentName', data.originalName)
    } catch (err) {
      setUploadError(err instanceof Error ? err.message : 'Upload failed')
    } finally {
      setUploading(false); e.target.value = ''
    }
  }

  switch (step.type) {
    case 'send_email':
      return (
        <div className="flex flex-col gap-2">
          <input className={inputCls} type="text" placeholder="Email subject"
            value={step.config.subject as string}
            onChange={e => onConfigChange('subject', e.target.value)} />
          <MergeTagPicker textareaRef={bodyRef} value={step.config.body as string} onChange={v => onConfigChange('body', v)} />
          <textarea ref={bodyRef} className={`${inputCls} resize-none font-mono`} rows={3}
            placeholder="Email body (HTML allowed)"
            value={step.config.body as string}
            onChange={e => onConfigChange('body', e.target.value)} />
          <input ref={fileRef} type="file" className="hidden" onChange={handleAttachment} />
          {uploadError && <p className="text-xs text-red-500">{uploadError}</p>}
          {step.config.attachmentName ? (
            <div className="flex items-center gap-2 text-xs text-charcoal-700">
              <Paperclip size={11} className="text-charcoal-400 shrink-0" />
              <span className="truncate flex-1">{step.config.attachmentName as string}</span>
              <button type="button" onClick={() => { onConfigChange('attachmentUrl', ''); onConfigChange('attachmentName', '') }}
                className="text-charcoal-400 hover:text-red-500"><X size={12} /></button>
            </div>
          ) : (
            <button type="button" disabled={uploading} onClick={() => fileRef.current?.click()}
              className="flex items-center gap-1.5 text-xs text-charcoal-500 hover:text-charcoal-800 disabled:opacity-50">
              <Paperclip size={13} /> {uploading ? 'UploadingΓÇª' : 'Attach a file'}
            </button>
          )}
        </div>
      )
    case 'send_sms':
      return (
        <textarea className={`${inputCls} resize-none`} rows={2} maxLength={160}
          placeholder="SMS message (max 160 chars)"
          value={step.config.body as string}
          onChange={e => onConfigChange('body', e.target.value)} />
      )
    case 'create_task':
      return (
        <div className="flex gap-2">
          <input className={`${inputCls} flex-1`} type="text" placeholder="Task title"
            value={step.config.title as string}
            onChange={e => onConfigChange('title', e.target.value)} />
          <select className={`${inputCls} w-28`} value={step.config.priority as string}
            onChange={e => onConfigChange('priority', e.target.value)}>
            {['low','normal','high','urgent'].map(p => <option key={p} value={p}>{p}</option>)}
          </select>
        </div>
      )
    case 'update_lead_score':
      return (
        <div className="flex items-center gap-2">
          <label className="text-xs text-charcoal-500 shrink-0">Score delta</label>
          <input className={`${inputCls} w-24`} type="number"
            value={step.config.delta as number}
            onChange={e => onConfigChange('delta', parseInt(e.target.value) || 0)} />
          <span className="text-xs text-charcoal-400">(negative to deduct)</span>
        </div>
      )
  }
}

// ΓöÇΓöÇ SpecialEventBuilder ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export function SpecialEventBuilder({ onCreated, onUpdated, campaignId, initialData }: Props) {
  const isEdit = Boolean(campaignId)

  const [name,        setName]        = useState(initialData?.name        ?? '')
  const [description, setDescription] = useState(initialData?.description ?? '')
  const [steps,       setSteps]       = useState<EventStep[]>(
    initialData?.steps?.length
      ? initialData.steps.map(parseExistingStep)
      : [emptyStep(0)]
  )
  const [saving, setSaving] = useState(false)
  const [error,  setError]  = useState('')

  function addStep() {
    setSteps(prev => [...prev, emptyStep(prev.length)])
  }

  function removeStep(i: number) {
    setSteps(prev => prev.filter((_, idx) => idx !== i).map((s, idx) => ({ ...s, order: idx })))
  }

  function updateStep(i: number, patch: Partial<EventStep>) {
    setSteps(prev => prev.map((s, idx) => {
      if (idx !== i) return s
      const updated = { ...s, ...patch }
      if (patch.type && patch.type !== s.type) updated.config = defaultConfig(patch.type)
      return updated
    }))
  }

  function updateConfig(i: number, key: string, value: string | number) {
    setSteps(prev => prev.map((s, idx) =>
      idx === i ? { ...s, config: { ...s.config, [key]: value } } : s
    ))
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    if (!name.trim()) { setError('Campaign name is required'); return }
    if (steps.length === 0) { setError('Add at least one step'); return }
    setSaving(true); setError('')

    try {
      // Merge schedule fields into config before sending
      const apiSteps = steps.map(s => ({
        order:        s.order,
        type:         s.type,
        delayMinutes: 0,
        config: {
          ...s.config,
          scheduleType: s.scheduleType,
          offsetDays:   s.offsetDays,
          ...(s.scheduleType === 'fixed_date' && { fixedMonth: s.fixedMonth, fixedDay: s.fixedDay }),
        },
      }))

      const url    = isEdit ? `/api/campaigns/${campaignId}` : '/api/campaigns'
      const method = isEdit ? 'PATCH' : 'POST'

      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name, description, trigger: 'special_event', steps: apiSteps }),
      })

      if (!res.ok) {
        let message = `Failed to ${isEdit ? 'update' : 'create'} campaign`
        try {
          const json = await res.json()
          if (json.error) message = typeof json.error === 'string' ? json.error : JSON.stringify(json.error)
        } catch { /* empty body */ }
        throw new Error(message)
      }

      isEdit ? onUpdated?.() : onCreated?.()
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Something went wrong')
    } finally {
      setSaving(false)
    }
  }

  return (
    <form onSubmit={handleSubmit} className="flex flex-col gap-5">
      {/* Metadata */}
      <div className="grid grid-cols-2 gap-4">
        <div className="col-span-2">
          <label className="text-xs text-charcoal-500 mb-1 block">Campaign Name *</label>
          <input type="text" value={name} onChange={e => setName(e.target.value)}
            placeholder="e.g. Birthday & Anniversary Touches"
            className="w-full rounded-lg border border-charcoal-200 bg-white px-3 py-2 text-sm text-charcoal-900 placeholder:text-charcoal-400 focus:outline-none focus:ring-2 focus:ring-charcoal-900" />
        </div>
        <div className="col-span-2">
          <label className="text-xs text-charcoal-500 mb-1 block">Description (optional)</label>
          <input type="text" value={description} onChange={e => setDescription(e.target.value)}
            placeholder="Brief description"
            className="w-full rounded-lg border border-charcoal-200 bg-white px-3 py-2 text-sm text-charcoal-900 placeholder:text-charcoal-400 focus:outline-none focus:ring-2 focus:ring-charcoal-900" />
        </div>
      </div>

      {/* Steps */}
      <div>
        <div className="flex items-center justify-between mb-2">
          <p className="text-xs font-semibold text-charcoal-700 uppercase tracking-wide">Steps</p>
          <button type="button" onClick={addStep}
            className="flex items-center gap-1 text-xs text-gold-600 hover:text-gold-700 font-medium">
            <Plus size={12} /> Add Step
          </button>
        </div>

        <div className="flex flex-col gap-3">
          {steps.map((step, i) => (
            <div key={i} className="rounded-xl border border-charcoal-200 bg-charcoal-50 p-3">

              {/* Row 1: step number + action type + remove */}
              <div className="flex items-center gap-2 mb-3">
                <span className="flex h-5 w-5 items-center justify-center rounded-full bg-charcoal-200 text-xs font-bold text-charcoal-700 shrink-0">
                  {i + 1}
                </span>
                <select value={step.type}
                  onChange={e => updateStep(i, { type: e.target.value as ActionType })}
                  className="flex-1 rounded-lg border border-charcoal-200 bg-white px-2 py-1 text-sm text-charcoal-900 focus:outline-none focus:ring-2 focus:ring-charcoal-900">
                  {Object.entries(ACTION_LABELS).map(([v, l]) => (
                    <option key={v} value={v}>{l}</option>
                  ))}
                </select>
                <button type="button" onClick={() => removeStep(i)}
                  className="text-red-400 hover:text-red-600 ml-1 shrink-0">
                  <Trash2 size={14} />
                </button>
              </div>

              {/* Row 2: schedule ΓÇö "Send X days before/after [event]" */}
              <div className="flex flex-wrap items-center gap-2 mb-3 bg-white rounded-lg border border-charcoal-200 px-3 py-2">
                <label className="text-xs text-charcoal-500 shrink-0">Send</label>

                {/* Offset value */}
                <input
                  type="number" min={0}
                  disabled={step.offsetDays === 0}
                  value={step.offsetDays === 0 ? '' : Math.abs(step.offsetDays)}
                  onChange={e => {
                    const abs = parseInt(e.target.value) || 0
                    updateStep(i, { offsetDays: step.offsetDays < 0 ? -abs : abs })
                  }}
                  className="w-14 rounded border border-charcoal-200 bg-charcoal-50 px-2 py-1 text-sm text-charcoal-900 focus:outline-none focus:ring-1 focus:ring-charcoal-900 disabled:opacity-40 disabled:cursor-not-allowed"
                />

                {/* Before / On / After */}
                <select
                  value={step.offsetDays === 0 ? 'on' : step.offsetDays < 0 ? 'before' : 'after'}
                  onChange={e => {
                    const abs = Math.abs(step.offsetDays) || 1
                    if (e.target.value === 'on')     updateStep(i, { offsetDays: 0 })
                    if (e.target.value === 'before') updateStep(i, { offsetDays: -abs })
                    if (e.target.value === 'after')  updateStep(i, { offsetDays:  abs })
                  }}
                  className="rounded border border-charcoal-200 bg-charcoal-50 px-2 py-1 text-sm text-charcoal-900 focus:outline-none focus:ring-1 focus:ring-charcoal-900">
                  <option value="before">days before</option>
                  <option value="on">days on</option>
                  <option value="after">days after</option>
                </select>

                {/* Event type */}
                <select value={step.scheduleType}
                  onChange={e => updateStep(i, { scheduleType: e.target.value as ScheduleType })}
                  className="rounded border border-charcoal-200 bg-charcoal-50 px-2 py-1 text-sm text-charcoal-900 focus:outline-none focus:ring-1 focus:ring-charcoal-900">
                  {Object.entries(SCHEDULE_LABELS).map(([v, l]) => (
                    <option key={v} value={v}>{l}</option>
                  ))}
                </select>

                {/* Fixed date pickers */}
                {step.scheduleType === 'fixed_date' && (
                  <>
                    <select value={step.fixedMonth}
                      onChange={e => updateStep(i, { fixedMonth: Number(e.target.value), fixedDay: Math.min(step.fixedDay, daysInMonth(Number(e.target.value))) })}
                      className="rounded border border-charcoal-200 bg-charcoal-50 px-2 py-1 text-sm text-charcoal-900 focus:outline-none focus:ring-1 focus:ring-charcoal-900">
                      {MONTHS.map((m, idx) => <option key={idx} value={idx + 1}>{m}</option>)}
                    </select>
                    <select value={step.fixedDay}
                      onChange={e => updateStep(i, { fixedDay: Number(e.target.value) })}
                      className="rounded border border-charcoal-200 bg-charcoal-50 px-2 py-1 text-sm text-charcoal-900 focus:outline-none focus:ring-1 focus:ring-charcoal-900">
                      {Array.from({ length: daysInMonth(step.fixedMonth) }, (_, d) => (
                        <option key={d + 1} value={d + 1}>{d + 1}</option>
                      ))}
                    </select>
                  </>
                )}
              </div>

              {/* Row 3: action content */}
              <StepActionConfig
                step={step}
                onChange={patch => updateStep(i, patch)}
                onConfigChange={(k, v) => updateConfig(i, k, v)}
              />
            </div>
          ))}
        </div>
      </div>

      {error && <p className="text-xs text-red-600">{error}</p>}

      <Button type="submit" variant="primary" loading={saving}
        leftIcon={isEdit ? <Save size={14} /> : <Star size={14} />}>
        {isEdit ? 'Save Changes' : 'Create Special Event Campaign'}
      </Button>
    </form>
  )
}

'use client'

/**
 * UnifiedTimeline
 *
 * Renders a single chronological feed mixing calls, SMS, emails, notes,
 * tasks, and activities. Each entry type has its own icon and colour so
 * agents can scan the full history at a glance.
 */

import {
  Mail, FileText, CheckSquare,
  ArrowRight, PhoneIncoming, PhoneOutgoing, PhoneMissed,
  Mic, ArrowDownLeft, ArrowUpRight, Zap, Users,
} from 'lucide-react'
import { formatDate } from '@/lib/utils'
import type { TimelineEntry, TimelineEntryType } from '@/lib/communications/timeline-service'

interface UnifiedTimelineProps {
  entries: TimelineEntry[]
}

type EntryConfig = {
  icon:  React.ReactNode
  color: string
  label: string
}

function getConfig(entry: TimelineEntry): EntryConfig {
  switch (entry.type) {
    case 'call': {
      const status = entry.status
      if (status === 'missed') return { icon: <PhoneMissed size={12} />, color: 'bg-red-100 text-red-600', label: 'Missed Call' }
      if (status === 'voicemail') return { icon: <Mic size={12} />, color: 'bg-amber-100 text-amber-600', label: 'Voicemail' }
      return entry.direction === 'inbound'
        ? { icon: <PhoneIncoming size={12} />, color: 'bg-blue-100 text-blue-600', label: 'Inbound Call' }
        : { icon: <PhoneOutgoing size={12} />, color: 'bg-blue-100 text-blue-600', label: 'Outbound Call' }
    }
    case 'sms':
      return entry.direction === 'inbound'
        ? { icon: <ArrowDownLeft size={12} />, color: 'bg-teal-100 text-teal-600', label: 'SMS Received' }
        : { icon: <ArrowUpRight  size={12} />, color: 'bg-teal-100 text-teal-600', label: 'SMS Sent' }
    case 'email':
      return { icon: <Mail size={12} />, color: 'bg-purple-100 text-purple-600', label: entry.direction === 'inbound' ? 'Email Received' : 'Email Sent' }
    case 'note':
      return { icon: <FileText size={12} />, color: 'bg-amber-100 text-amber-600', label: 'Note' }
    case 'task':
      return { icon: <CheckSquare size={12} />, color: 'bg-green-100 text-green-600', label: 'Task' }
    case 'enrollment':
      return { icon: <Users size={12} />, color: 'bg-indigo-100 text-indigo-600', label: 'Campaign Enrolled' }
    case 'campaign':
      return { icon: <Zap size={12} />, color: 'bg-violet-100 text-violet-600', label: 'Campaign Created' }
    case 'activity':
    default:
      return { icon: <ArrowRight size={12} />, color: 'bg-charcoal-100 text-charcoal-600', label: 'Activity' }
  }
}

function EntryItem({ entry }: { entry: TimelineEntry }) {
  const config = getConfig(entry)

  return (
    <div className="relative flex gap-4 pb-5">
      {/* Timeline dot */}
      <div className={`absolute -left-6 flex h-5 w-5 items-center justify-center rounded-full ring-2 ring-white ${config.color}`}>
        {config.icon}
      </div>
      {/* Content */}
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-2 mb-0.5">
          <span className="text-xs font-semibold text-charcoal-700">{config.label}</span>
          {entry.subject && <span className="text-xs text-charcoal-900 font-medium truncate">ΓÇö {entry.subject}</span>}
          {entry.status && entry.type !== 'email' && (
            <span className="text-xs text-charcoal-400 capitalize">({entry.status})</span>
          )}
        </div>

        {entry.body && (
          <p className="text-xs text-charcoal-500 line-clamp-2">{
            // Strip HTML tags for preview
            entry.body.replace(/<[^>]+>/g, ' ').trim()
          }</p>
        )}

        {/* Call duration */}
        {entry.type === 'call' && entry.durationSec && (
          <p className="text-xs text-charcoal-400 mt-0.5">
            Duration: {Math.floor(entry.durationSec / 60)}m {entry.durationSec % 60}s
          </p>
        )}

        {/* Email tracking stats */}
        {entry.type === 'email' && entry.meta && (
          <div className="flex gap-3 mt-0.5">
            {(entry.meta.openCount as number) > 0 && (
              <span className="text-xs text-green-600">{entry.meta.openCount as number} open{(entry.meta.openCount as number) !== 1 ? 's' : ''}</span>
            )}
            {(entry.meta.clickCount as number) > 0 && (
              <span className="text-xs text-blue-600">{entry.meta.clickCount as number} click{(entry.meta.clickCount as number) !== 1 ? 's' : ''}</span>
            )}
          </div>
        )}

        <div className="flex items-center gap-2 mt-1 text-xs text-charcoal-300">
          {entry.userName && <span>{entry.userName}</span>}
          {entry.contactName && (
            <>
              <span>┬╖</span>
              <span className="text-charcoal-400">{entry.contactName}</span>
            </>
          )}
          <span>┬╖</span>
          <span>{formatDate(new Date(entry.occurredAt), { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' })}</span>
        </div>
      </div>
    </div>
  )
}

export function UnifiedTimeline({ entries }: UnifiedTimelineProps) {
  if (entries.length === 0) {
    return <p className="text-sm text-charcoal-400 py-4">No communications yet. Log a call, send an SMS, or compose an email to get started.</p>
  }

  return (
    <div className="relative pl-6">
      <div className="absolute left-2 top-0 bottom-0 w-px bg-charcoal-100" />
      <div className="flex flex-col gap-0">
        {entries.map((entry) => (
          <EntryItem key={`${entry.type}-${entry.id}`} entry={entry} />
        ))}
      </div>
    </div>
  )
}

'use client'

import { useState } from 'react'
import { motion } from 'framer-motion'
import { CheckCircle } from 'lucide-react'
import { Button, Input, Select, Textarea } from '@/components/ui'

interface LeadCaptureFormProps {
  title?: string
  subtitle?: string
  source?: string
  onSuccess?: () => void
  variant?: 'light' | 'dark'
}

export function LeadCaptureForm({ title = 'Get in Touch', subtitle, source = 'website', onSuccess, variant = 'light' }: LeadCaptureFormProps) {
  const [form, setForm] = useState({ firstName: '', lastName: '', email: '', phone: '', interest: '', message: '' })
  const [loading, setLoading] = useState(false)
  const [success, setSuccess] = useState(false)
  const [error, setError] = useState('')

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)
    setError('')
    try {
      const res = await fetch('/api/contacts', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...form, source }),
      })
      if (!res.ok) throw new Error('Failed to submit')
      setSuccess(true)
      onSuccess?.()
    } catch {
      setError('Something went wrong. Please try again.')
    } finally {
      setLoading(false)
    }
  }

  if (success) {
    return (
      <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="flex flex-col items-center gap-4 py-8 text-center">
        <CheckCircle size={48} className="text-emerald-500" />
        <h3 className="font-serif text-2xl font-bold text-charcoal-900">Thank you!</h3>
        <p className="text-charcoal-500">We&apos;ll be in touch shortly.</p>
      </motion.div>
    )
  }

  return (
    <form onSubmit={handleSubmit} className="flex flex-col gap-4">
      {(title || subtitle) && (
        <div className="mb-2">
          {title && <h3 className="font-serif text-2xl font-bold text-charcoal-900">{title}</h3>}
          {subtitle && <p className="mt-1 text-charcoal-500">{subtitle}</p>}
        </div>
      )}
      <div className="grid grid-cols-2 gap-4">
        <Input label="First Name" required value={form.firstName} onChange={e => setForm(f => ({ ...f, firstName: e.target.value }))} />
        <Input label="Last Name" required value={form.lastName} onChange={e => setForm(f => ({ ...f, lastName: e.target.value }))} />
      </div>
      <Input label="Email" type="email" required value={form.email} onChange={e => setForm(f => ({ ...f, email: e.target.value }))} />
      <Input label="Phone" type="tel" value={form.phone} onChange={e => setForm(f => ({ ...f, phone: e.target.value }))} />
      <Select
        label="I'm looking toΓÇª"
        value={form.interest}
        onChange={e => setForm(f => ({ ...f, interest: e.target.value }))}
        options={[
          { value: 'buy', label: 'Buy a Home' },
          { value: 'sell', label: 'Sell a Home' },
          { value: 'invest', label: 'Invest in Real Estate' },
          { value: 'rent', label: 'Rent' },
          { value: 'other', label: 'Other' },
        ]}
        placeholder="Select an option"
      />
      <Textarea label="Message (optional)" value={form.message} onChange={e => setForm(f => ({ ...f, message: e.target.value }))} rows={3} />
      {error && <p className="text-sm text-red-600">{error}</p>}
      <Button type="submit" variant="gold" size="lg" loading={loading} fullWidth>
        Send Message
      </Button>
    </form>
  )
}

